import React, {useState} from 'react';
import ProjectList from './../components/ProjectList';
import Masonry from 'react-masonry-css';

function Home(){
  const [projects, setProjects] = useState([
    {
      id: 1,
      name: "Booklandia",
      desc: "Website",
      img: "img/works/booklandia-site.png",
    },
    {
      id: 2,
      name: "TESDA Women's Center",
      desc: "Website",
      img: "img/works/twc.png",
    },
    {
      id: 3,
      name: "Booklandia",
      desc: "Website",
      img: "img/works/fun-run.png",
    },
    {
      id: 4,
      name: "Finest Aluminum Catalogue",
      desc: "Design",
      img: "img/works/finest-catalogue.png",
    },
    {
      id: 5,
      name: "Finest Aluminum Brochure",
      desc: "Design",
      img: "img/works/finest-brochure.png",
    },
    {
      id: 6,
      name: "P&G Events",
      desc: "Design",
      img: "img/works/PandG.png",
    },
    {
      id: 7,
      name: "DEPED K12 Infographics",
      desc: "Design",
      img: "img/works/k12.png",
    },
    {
      id: 8,
      name: "Famrun 2018",
      desc: "Design",
      img: "img/works/fun-run.png",
    }
  ])

  return(
  			<main id="main">
  				<div className="main-outer">
  					<div className="container-fluid">
  						<div className="row">
  							<div className="col-md-12">
  								<div id="works-grid">
  									<div className="gutter"></div>
  									<ProjectList />
  								</div>
  							</div>
  						</div>
  					</div>
  				</div>
  			</main>
  );
}
export default Home
